// 按钮类型
type ButtonType = 'primary' // 主题色
  | 'default'  // 默认
  | 'warn'     // 警告
  | 'danger'   // 危险
  | 'safe'     // 安全
// 按钮形态
type ButtonVariant = 'base' // 填充
  | 'outline'  // 实线边框
  | 'dashed'  // 虚线边框
  | 'text'  //纯文本
// 按钮形状
type ButtonShape = 'round' // 圆角
  | 'rectangle' // 矩形
  | 'circle'   // 圆形
  | 'square'  // 正方形
// 按钮大小
type ButtonSize = 'medium' // 中等
  | 'large' // 大
  | 'small' // 小